from lxml import etree

def process_soap_request(xml_request):
    # Parse the incoming XML request
    parser = etree.XMLParser(load_dtd=True, resolve_entities=False)
    root = etree.fromstring(xml_request.encode('utf-8'), parser)
    
    # Validate against DTD (assuming a DTD file is provided)
    dtd = etree.DTD('soap_request.dtd')
    if not dtd.validate(root):
        raise ValueError("Invalid XML according to DTD: " + str(dtd.error_log))
    
    # Extract the SOAP body
    namespaces = {'soap': 'http://schemas.xmlsoap.org/soap/envelope/'}
    body = root.find('.//soap:Body', namespaces)
    
    if body is not None:
        return etree.tostring(body, pretty_print=True).decode('utf-8')
    else:
        raise ValueError("SOAP Body not found in the request")